"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { api, type MenuItem } from "@/lib/api";

const TOAST_KEY = "items_toast";

export function ItemsList() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [items, setItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [includeDeleted, setIncludeDeleted] = useState(searchParams.get("includeDeleted") === "1");

  useEffect(() => {
    const msg = typeof sessionStorage !== "undefined" ? sessionStorage.getItem(TOAST_KEY) : null;
    if (msg) {
      sessionStorage.removeItem(TOAST_KEY);
      setSuccess(msg);
      const t = setTimeout(() => setSuccess(""), 3000);
      return () => clearTimeout(t);
    }
  }, []);

  function refresh() {
    setLoading(true);
    api
      .getItems(includeDeleted)
      .then(setItems)
      .catch((e) => setError(e instanceof Error ? e.message : "Failed to load"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    setIncludeDeleted(searchParams.get("includeDeleted") === "1");
  }, [searchParams]);

  useEffect(() => {
    refresh();
  }, [includeDeleted]);

  async function handleDelete(item: MenuItem) {
    if (!confirm(`Delete "${item.name}"?`)) return;
    setError("");
    setSuccess("");
    try {
      await api.deleteItem(item.id);
      setSuccess("Item deleted");
      refresh();
      setTimeout(() => setSuccess(""), 3000);
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Failed to delete";
      setError(msg);
      console.error("[handleDelete item] failed:", { itemId: item.id, error: e });
    }
  }

  async function handleRestore(item: MenuItem) {
    if (!confirm(`Restore "${item.name}"?`)) return;
    setError("");
    setSuccess("");
    try {
      await api.restoreItem(item.id);
      setSuccess("Item restored");
      refresh();
      setTimeout(() => setSuccess(""), 3000);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to restore");
    }
  }

  const API = process.env.NEXT_PUBLIC_API_URL || "http://localhost:4000";

  return (
    <div className="space-y-3">
      <div className="flex flex-wrap items-center gap-3">
        <label className="flex items-center gap-2 text-sm text-gray-600">
          <input
            type="checkbox"
            checked={includeDeleted}
            onChange={(e) => {
              const v = e.target.checked;
              setIncludeDeleted(v);
              const url = new URL(window.location.href);
              if (v) url.searchParams.set("includeDeleted", "1");
              else url.searchParams.delete("includeDeleted");
              router.replace(url.pathname + url.search, { scroll: false });
            }}
            className="rounded border-gray-300"
          />
          Show deleted
        </label>
        {success && <p className="text-green-600 text-sm">{success}</p>}
        {error && <p className="text-red-600 text-sm">{error}</p>}
      </div>
      {loading && <p className="text-gray-500">Loading…</p>}
      {!loading && (
    <div className="overflow-x-auto rounded border bg-white">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Image</th>
            <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Name</th>
            <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Category</th>
            <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Price (₱)</th>
            <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Active</th>
            <th className="px-4 py-2 text-right text-xs font-medium uppercase text-gray-500">Actions</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-200">
          {items.map((item) => (
            <tr key={item.id} className={`hover:bg-gray-50 ${item.deletedAt ? "bg-gray-100 opacity-75" : ""}`}>
              <td className="px-4 py-3">
                {item.imageUrl ? (
                  <img
                    src={item.imageUrl.startsWith("http") ? item.imageUrl : `${API}${item.imageUrl}`}
                    alt=""
                    className="h-10 w-10 rounded object-cover"
                  />
                ) : (
                  <span className="text-gray-400 text-xs">—</span>
                )}
              </td>
              <td className="px-4 py-3 text-sm text-gray-900">{item.name}</td>
              <td className="px-4 py-3 text-sm text-gray-600">
                {item.category?.name ?? item.subCategory?.name ?? "—"}
              </td>
              <td className="px-4 py-3 text-sm text-gray-600">₱{(item.priceCents / 100).toFixed(2)}</td>
              <td className="px-4 py-3 text-sm">{item.isActive ? "Yes" : "No"}</td>
              <td className="px-4 py-3 text-right">
                {item.deletedAt ? (
                  <>
                    <Link href={`/items/${item.id}?includeDeleted=1`} className="mr-3 text-blue-600 hover:underline">View</Link>
                    <button
                      type="button"
                      onClick={() => handleRestore(item)}
                      className="mr-3 text-green-600 hover:underline"
                    >
                      Restore
                    </button>
                  </>
                ) : (
                  <>
                    <Link href={`/items/${item.id}`} className="mr-3 text-blue-600 hover:underline">Edit</Link>
                    <button
                      type="button"
                      onClick={() => handleDelete(item)}
                      className="text-red-600 hover:underline"
                    >
                      Delete
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {items.length === 0 && (
        <p className="px-4 py-6 text-center text-gray-500">
          {includeDeleted ? "No items (including deleted)." : "No items yet."}
        </p>
      )}
    </div>
      )}
    </div>
  );
}
